class TestPredictionHealthEndpoint:
    """GET /v1/prediction/health — always HTTP 200, no DB writes, no predictions run."""

    def test_prediction_health_service_ok(
        self, client: TestClient, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        """Mocked healthy prediction service → status 'ok'."""
        class _WithUrl:
            service_api_key = _TEST_API_KEY
            stock_prediction_api_url = "http://127.0.0.1:9000"
            stock_prediction_api_timeout_seconds = 5

        monkeypatch.setattr("paper_trader.api.app.get_settings", lambda: _WithUrl())
        monkeypatch.setattr(
            "paper_trader.api.app._check_prediction_healthz",
            lambda base_url, timeout_seconds=5: (True, True, "Prediction service healthy"),
        )
        resp = client.get("/v1/prediction/health", headers=_AUTH)
        assert resp.status_code == 200
        data = resp.json()
        assert data["status"] == "ok"
        assert data["reachable"] is True
        assert data["healthz_ok"] is True
        assert "expected_tunnel_command" in data
        assert "gcloud" in data["expected_tunnel_command"]
        assert "checked_at" in data

    def test_prediction_health_service_unreachable(
        self, client: TestClient, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        """Mocked unreachable service → status 'unavailable'."""
        class _WithUrl:
            service_api_key = _TEST_API_KEY
            stock_prediction_api_url = "http://127.0.0.1:9000"
            stock_prediction_api_timeout_seconds = 5

        monkeypatch.setattr("paper_trader.api.app.get_settings", lambda: _WithUrl())
        monkeypatch.setattr(
            "paper_trader.api.app._check_prediction_healthz",
            lambda base_url, timeout_seconds=5: (False, False, "Unreachable: Connection refused"),
        )
        resp = client.get("/v1/prediction/health", headers=_AUTH)
        assert resp.status_code == 200
        data = resp.json()
        assert data["status"] == "unavailable"
        assert data["reachable"] is False
        assert data["healthz_ok"] is False
        assert "gcloud" in data["expected_tunnel_command"]
        assert "Unreachable" in data["detail"]

    def test_prediction_health_no_url_configured(
        self, client: TestClient, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        """Empty prediction URL → status 'misconfigured', no network call made."""
        class _EmptyUrlSettings:
            service_api_key = _TEST_API_KEY
            stock_prediction_api_url = ""
            stock_prediction_api_timeout_seconds = 5

        monkeypatch.setattr("paper_trader.api.app.get_settings", lambda: _EmptyUrlSettings())
        resp = client.get("/v1/prediction/health", headers=_AUTH)
        assert resp.status_code == 200
        data = resp.json()
        assert data["status"] == "misconfigured"
        assert data["reachable"] is False
        assert data["healthz_ok"] is False
        assert data["prediction_base_url"] == ""
        assert "gcloud" in data["expected_tunnel_command"]

    def test_prediction_health_requires_auth(self, client: TestClient) -> None:
        """Missing API key → 401."""
        resp = client.get("/v1/prediction/health")
        assert resp.status_code == 401


# ===========================================================================
# TestManualPaperFillEndpoint
# ===========================================================================

class TestManualPaperFillEndpoint:
    """Tests for POST /v1/review/fill-pending-orders (PAPER FILLS ONLY, no broker)."""

    _ENDPOINT = "/v1/review/fill-pending-orders"

    @pytest.fixture(autouse=True)
    def _cleanup_fill_artifacts(self, api_engine):
        """Delete paper order ticket rows and any stray PENDING orders for today's
        market_date before and after each test.

        Two-clause deletion ensures isolation even when other test classes leave
        PENDING orders without a 'Paper order ticket' notes marker (e.g. the QCOM
        order created in TestOrderPreviewEndpoint with no cleanup).
        """
        def _purge():
            from zoneinfo import ZoneInfo
            _eastern = ZoneInfo("America/New_York")
            # Use same market_date calculation as endpoints
            today = datetime.now(timezone.utc).astimezone(_eastern).date()
            with Session(api_engine, autoflush=False, expire_on_commit=False) as s:
                # Delete all paper-ticket orders regardless of status
                s.query(Order).filter(
                    Order.notes.like("Paper order ticket%"),
                ).delete(synchronize_session=False)
                # Also delete any stray PENDING orders for today from other test classes
                s.query(Order).filter(
                    Order.status == "PENDING",
                    Order.market_date == today,
                ).delete(synchronize_session=False)
                s.commit()

        _purge()
        yield
        _purge()

    # ------------------------------------------------------------------
    # Helper: seed a complete Signal→TradeDecision→PriceSnapshot→Order chain
    # ------------------------------------------------------------------

    @staticmethod
    def _seed_pending_order(
        session,
        suffix: str,
        *,
        side: str = "BUY",
        qty: Decimal = Decimal("5.00000000"),
        price: Decimal = Decimal("100.00"),
        market_date: date | None = None,
    ) -> tuple:
        """
        Create a PENDING paper Order row with all required FKs.
        Returns (order_id, ticker, td_id).
        """
        import uuid as _uuid
        from zoneinfo import ZoneInfo

        _eastern = ZoneInfo("America/New_York")
        md = market_date or datetime.now(timezone.utc).astimezone(_eastern).date()
        ticker = f"FILL{suffix[:5]}".upper()

        jr_sig = JobRun(
            idempotency_key=f"fill-sig-jr-{suffix}",
            workflow_type="REVIEW_QUEUE_CREATE_SIGNALS",
            market_date=md,
            status="COMPLETED",
            completed_at=datetime.now(timezone.utc),
        )
        session.add(jr_sig)
        session.flush()

        sig = Signal(
            job_run_id=jr_sig.id,
            ticker=ticker,
            direction=side,
            confidence=Decimal("0.85"),
            signal_ts=datetime.now(timezone.utc),
            market_date=md,
            source_run=f"review_queue_create_signals_v1:fill:{suffix}",
            status="RECEIVED",
            raw_payload={},
        )
        session.add(sig)
        session.flush()

        snap = PriceSnapshot(
            ticker=ticker,
            price=price,
            session_type="REGULAR",
            price_type="CLOSE",
            market_date=md,
            snapshot_ts=datetime.now(timezone.utc),
        )
        session.add(snap)
        session.flush()

        jr_td = JobRun(
            idempotency_key=f"fill-td-jr-{suffix}",
            workflow_type="REVIEW_QUEUE_CREATE_DECISIONS",
            market_date=md,
            status="COMPLETED",
            completed_at=datetime.now(timezone.utc),
        )
        session.add(jr_td)
        session.flush()

        td = TradeDecision(
            signal_id=sig.id,
            job_run_id=jr_td.id,
            ticker=ticker,
            signal_direction=side,
            decision=side,
            reason_code=None,
            approved_qty=qty,
            approved_notional=(qty * price).quantize(Decimal("0.01")),
            requested_qty=qty,
            requested_notional=(qty * price).quantize(Decimal("0.01")),
            decided_at=datetime.now(timezone.utc),
            market_date=md,
        )
        session.add(td)
        session.flush()

        jr_ord = JobRun(
            idempotency_key=f"fill-ord-jr-{suffix}",
            workflow_type="REVIEW_QUEUE_CREATE_ORDERS",
            market_date=md,
            status="COMPLETED",
            completed_at=datetime.now(timezone.utc),
        )
        session.add(jr_ord)
        session.flush()

        order = Order(
            trade_decision_id=td.id,
            job_run_id=jr_ord.id,
            ticker=ticker,
            side=side,
            order_type="MARKET",
            status="PENDING",
            market_date=md,
            requested_qty=qty,
            requested_at=datetime.now(timezone.utc),
            notes="Paper order ticket — review workflow. No broker execution.",
        )
        session.add(order)
        session.flush()

        return order.id, ticker, td.id

    # ------------------------------------------------------------------
    # Test 1: unauthorized
    # ------------------------------------------------------------------

    def test_unauthorized_returns_401(self, seeded_client: TestClient) -> None:
        r = seeded_client.post(self._ENDPOINT, json={"confirm_paper_fill": True})
        assert r.status_code == 401

    # ------------------------------------------------------------------
    # Test 2: confirm_paper_fill=False returns 422
    # ------------------------------------------------------------------

    def test_confirm_false_returns_422(self, seeded_client: TestClient) -> None:
        r = seeded_client.post(
            self._ENDPOINT,
            json={"confirm_paper_fill": False},
            headers=_AUTH,
        )
