class TestScanDiagnosticsCaptureLinkage:
    """Scan Selection Funnel reports REAL per-session prediction capture counts.

    Linkage is exact (prediction_runs.daily_session_id == latest
    CandidateReview.idempotency_key), never timestamp guessing. All read-only:
    counting capture rows creates no signals/decisions/orders/trades.
    """

    _ENDPOINT = "/v1/review/scan-diagnostics/latest"

    @staticmethod
    def _sfx() -> str:
        import uuid as _uuid
        return _uuid.uuid4().hex[:8]

    @staticmethod
    def _save_and_clear_candidate_reviews(session) -> list[dict]:
        from sqlalchemy import inspect as _sa_inspect
        col_keys = [c.key for c in _sa_inspect(CandidateReview).mapper.column_attrs]
        saved = [
            {k: getattr(r, k) for k in col_keys}
            for r in session.execute(select(CandidateReview)).scalars().all()
        ]
        session.query(CandidateReview).delete(synchronize_session=False)
        return saved

    def _capture_row(self, ticker, session_id, *, error=False):
        now = datetime.now(timezone.utc)
        return PredictionRun(
            ticker=ticker,
            daily_session_id=session_id,
            source="DAILY_REVIEW",
            request_ts=now,
            response_ts=now,
            latency_ms=20,
            prediction_service_url="http://127.0.0.1:9000/predict_all_models/",
            request_payload={"ticker": ticker},
            http_status=None if error else 200,
            raw_response=None if error else {"ticker": ticker},
            error=error,
            error_message="timeout" if error else None,
        )

    def _run(self, seeded_client, api_engine, *, review_status, error_rows):
        """Seed one session + capture rows, return the funnel JSON. Restores DB."""
        sfx = self._sfx()
        key = f"daily-session-{sfx}"
        with Session(api_engine, autoflush=False, expire_on_commit=False) as session:
            saved = self._save_and_clear_candidate_reviews(session)
            try:
                session.add(CandidateReview(
                    idempotency_key=key, ticker=f"CAP{sfx[:3].upper()}",
                    prediction_recommendation="BUY", prediction_confidence="0.85",
                    expected_return_pct="5.0", preview_decision="CONSIDER",
                    preview_score="85.0", review_status=review_status, status="OK",
                ))
                for i in range(2):
                    session.add(self._capture_row(f"CAPX{i}{sfx[:2].upper()}", key, error=error_rows))
                session.commit()

                resp = seeded_client.get(self._ENDPOINT, headers=_AUTH)
                assert resp.status_code == 200
                data = resp.json()
            finally:
                session.query(PredictionRun).filter(
                    PredictionRun.daily_session_id == key
                ).delete(synchronize_session=False)
                session.query(CandidateReview).filter(
                    CandidateReview.idempotency_key == key
                ).delete(synchronize_session=False)
                for rowdict in saved:
                    session.add(CandidateReview(**rowdict))
                session.commit()
        return data, key

    def test_captured_with_active_idea(self, seeded_client, api_engine):
        data, key = self._run(
            seeded_client, api_engine, review_status="NEW", error_rows=False
        )
        assert data["session_id"] == key
        assert data["capture_session_linked"] is True
        assert data["predictions_captured"] == 2
        assert data["sent_to_prediction"] == 2
        assert data["sent_to_prediction_captured"] is True
        assert data["predictions_returned"] == 2
        assert data["predictions_returned_captured"] is True
        assert data["capture_status"] == "CAPTURED"
        # Never the misleading bare label when rows are linked.
        assert "not captured yet" not in data["capture_status_message"].lower()

    def test_captured_but_none_passed_gate(self, seeded_client, api_engine):
        data, key = self._run(
            seeded_client, api_engine, review_status="WATCHING", error_rows=False
        )
        assert data["predictions_captured"] == 2
        assert data["active_trade_ideas"] == 0
        assert data["capture_status"] == "NONE_PASSED_GATE"
        # Count-bearing message (req #5/#8): the captured number is stated.
        assert data["capture_status_message"] == (
            "2 predictions captured. None passed the actionability gate."
        )

    def test_dispatch_failed(self, seeded_client, api_engine):
        data, key = self._run(
            seeded_client, api_engine, review_status="NEW", error_rows=True
        )
        assert data["predictions_captured"] == 2
        assert data["prediction_errors_captured"] == 2
        assert data["capture_status"] == "DISPATCH_FAILED"
        assert data["predictions_returned"] == 0

    def test_zero_candidate_session_links_via_prediction_runs(
        self, seeded_client, api_engine
    ):
        """A 0-candidate Daily Review saves NO CandidateReview, but its captured
        prediction_runs still become the resolved latest session via the newer
        daily_session_id — instead of falling back to a stale CandidateReview.

        This is the v2 funnel fix: "7 predictions captured. None passed the
        actionability gate." linked to the just-run session, not "Not captured
        for this older session."
        """
        sfx = self._sfx()
        new_key = f"daily-session-NEW-{sfx}"
        old_key = f"daily-session-OLD-{sfx}"
        with Session(api_engine, autoflush=False, expire_on_commit=False) as session:
            saved = self._save_and_clear_candidate_reviews(session)
            try:
                # Older candidate review from a prior session (created in the past).
                old_cr = CandidateReview(
                    idempotency_key=old_key, ticker=f"OLD{sfx[:3].upper()}",
                    prediction_recommendation="BUY", prediction_confidence="0.85",
                    expected_return_pct="5.0", preview_decision="CONSIDER",
                    preview_score="85.0", review_status="REJECTED", status="OK",
                )
                session.add(old_cr)
                session.flush()
                old_cr.created_at = datetime.now(timezone.utc) - timedelta(days=2)
                # The just-run session captured 7 predictions but saved 0 candidates.
                for i in range(7):
                    session.add(self._capture_row(
                        f"NEW{i}{sfx[:2].upper()}", new_key, error=False
                    ))
                session.commit()

                resp = seeded_client.get(self._ENDPOINT, headers=_AUTH)
                assert resp.status_code == 200
                data = resp.json()
            finally:
                session.query(PredictionRun).filter(
                    PredictionRun.daily_session_id == new_key
                ).delete(synchronize_session=False)
                session.query(CandidateReview).filter(
                    CandidateReview.idempotency_key == old_key
                ).delete(synchronize_session=False)
                for rowdict in saved:
                    session.add(CandidateReview(**rowdict))
                session.commit()

        # The newer DAILY_REVIEW prediction-run session wins over the stale CR.
        assert data["session_id"] == new_key
        assert data["prediction_run_session_id"] == new_key
        assert data["candidate_review_idempotency_key"] == old_key
        assert data["prediction_runs_matched_count"] == 7
        assert data["predictions_captured"] == 7
        assert data["predictions_returned"] == 7
        assert data["capture_session_linked"] is True
        assert data["active_trade_ideas"] == 0
        assert data["capture_status"] == "NONE_PASSED_GATE"
        assert "7 predictions captured" in data["capture_status_message"]
        assert "None passed the actionability gate." in data["capture_status_message"]
        # Never the misleading older-session label when the session is linked.
        assert "older session" not in data["capture_status_message"].lower()


class TestUiDailyAlphaRunPanelContent:
    """Phase 13-G/H: the "DAILY ALPHA RUN" manual daily trading-desk cockpit in
    index.html.

    Static-content assertions over api/ui/index.html — no HTTP needed. Verify the
    prominent RUN DAILY ALPHA REFRESH action, the eight safety badges + banner, the
    operating-status + per-book KPI + chart surfaces, the actual audited universe
    identity (and the S&P 500 shadow shown separately), that the panel POSTs only to
    daily-refresh and GETs daily-status / pnl-history (never orders / signals /
    decisions), and that it uses no alert()/confirm().
    """

    _START = "Daily Alpha Run (Phase 13-G/H) START"
    _END = "Daily Alpha Run (Phase 13-G/H) END"

    @staticmethod
    def _read_html() -> str:
        from pathlib import Path
        html_path = Path(__file__).parent.parent / "api" / "ui" / "index.html"
        return html_path.read_text(encoding="utf-8", errors="ignore")

    @classmethod
    def _markup(cls) -> str:
        html = cls._read_html()
        start = html.index('id="cad-panel"')
        end = html.index(cls._END, start)
        return html[start:end]

    @classmethod
    def _js(cls) -> str:
        html = cls._read_html()
        start = html.index("// ===== " + cls._START)
        end = html.index("// ===== " + cls._END)
        return html[start:end]

    def test_panel_and_headline_present(self) -> None:
        html = self._read_html()
        assert 'id="cad-panel"' in html
        assert "DAILY ALPHA RUN" in html
        assert "RUN DAILY ALPHA REFRESH" in html

    def test_primary_action_wired(self) -> None:
        markup = self._markup()
        assert 'id="cad-run-btn"' in markup
        assert "runDailyAlphaRefresh(this)" in markup
        assert 'id="cad-status-btn"' in markup
        assert "loadDailyAlphaStatus(this)" in markup

    def test_required_safety_text_present(self) -> None:
        markup = self._markup()
        for phrase in (
            "MANUAL DAILY REFRESH", "PAPER TEST ONLY", "NO ORDERS", "NO BROKER",
            "NO AUTOMATION", "DOES NOT CREATE SIGNALS", "DOES NOT CREATE TRADE DECISIONS",
            "DOES NOT EXECUTE TRADES",
        ):
            assert phrase in markup, f"missing required safety text: {phrase}"

    def test_operating_status_and_kpi_surfaces_present(self) -> None:
        markup = self._markup()
        for el_id in ("cad-last-run", "cad-mark-date", "cad-price-source", "cad-freshness",
                      "cad-top25-metrics", "cad-top50-metrics",
                      "cad-chart-top25", "cad-chart-top50", "cad-chart-spy",
                      "cad-action-result", "cad-warnings"):
            assert f'id="{el_id}"' in markup, f"missing surface: {el_id}"
        # human-readable operating labels
        for label in ("Last daily run", "Latest price mark", "Price source",
                      "Mark freshness"):
            assert label in markup, f"missing operating label: {label}"

    def test_states_actual_universe_identity_and_shadow(self) -> None:
        markup = self._markup()
        assert "CURRENT CHAMPION UNIVERSE" in markup
        assert 'id="cad-universe-name"' in markup
        # the S&P 500 shadow is shown separately, never merged with the champion
        assert "S&amp;P 500 SHADOW — RESEARCH COMPARISON" in markup
        assert 'id="cad-shadow"' in markup

    def test_charts_use_eod_price_mark_axis(self) -> None:
        markup = self._markup()
        assert "per EOD price mark" in markup
        js = self._js()
        # the chart x-axis label is the owned EOD price-mark date, never the observation date
        assert "s.as_of_price_date" in js

    def test_posts_only_to_daily_refresh_and_reads_status(self) -> None:
        js = self._js()
        assert "/v1/research/current-alpha/daily-refresh" in js
        assert "/v1/research/current-alpha/daily-status" in js
        # never posts to orders / signals / decisions
        for forbidden in ("/v1/orders", "/v1/signals", "/v1/decisions",
                          "create_order", "place_order"):
            assert forbidden not in js, f"forbidden endpoint/token in cad JS: {forbidden}"

    def test_no_blocking_dialogs(self) -> None:
        import re
        js = self._js()
        assert not re.search(r"(?<![A-Za-z0-9_])alert\s*\(", js)
        assert not re.search(r"(?<![A-Za-z0-9_])confirm\s*\(", js)

    def test_distinguishes_current_run_from_latest_valid_mark(self) -> None:
        # The panel must present the CURRENT RUN result and the LATEST VALID PRICE MARK
        # as two distinct labels (the process-boundary fix, surfaced to the user).
        markup = self._markup()
        assert "LAST RUN RESULT" in markup
        assert "LATEST VALID PRICE MARK" in markup
        assert 'id="cad-last-run-result"' in markup
        assert 'id="cad-valid-mark-date"' in markup

    def test_required_same_date_and_blocked_messages(self) -> None:
        # The required same-date and blocked run messages, verbatim, in the panel JS.
        js = self._js()
        assert "NO NEW COMPLETED EOD DATE — NO SNAPSHOT ADDED" in js
        assert "DAILY REFRESH BLOCKED — LAST VALID MARK PRESERVED" in js
        # driven by the current-run status fields (not the financial manifest)
        assert "last_run_result" in js
        assert "latest_valid_mark_date" in js


